INSERT OR IGNORE INTO body_target_info (slug, lang, title, "desc") VALUES
('quadriceps', 'es', 'Cuádriceps', 'Grupo muscular en la parte anterior del muslo formado por cuatro cabezas (recto femoral, vasto lateral, medial e intermedio), esencial para la extensión de la rodilla y estabilidad postural.'),
('quadriceps', 'en', 'Quads', 'Muscle group on the front of the thigh consisting of four heads (rectus femoris, vastus lateralis, medialis, and intermedius), essential for knee extension and postural stability.'),
('quadriceps', 'pt', 'Quadríceps', 'Grupo muscular na parte anterior da coxa formado por quatro cabeças (reto femoral, vasto lateral, medial e intermédio), essencial para a extensão do joelho e estabilidade postural.'),
('quadriceps', 'fr', 'Quadriceps', 'Groupe musculaire de la partie antérieure de la cuisse formé de quatre chefs (droit fémoral, vastes latéral, médial et intermédiaire), essentiel pour l extension du genou et la stabilité posturale.'),
('quadriceps', 'de', 'Quadrizeps', 'Muskelgruppe an der Vorderseite des Oberschenkels, bestehend aus vier Köpfen (Musculus rectus femoris, vastus lateralis, medialis und intermedius), entscheidend für die Kniebeugung und Haltungsstabilität.'),
('quadriceps', 'it', 'Quadricipiti', 'Gruppo muscolare nella parte anteriore della coscia formato da quattro capi (retto femorale, vasto laterale, mediale e intermedio), essenziale per l estensione del ginocchio e la stabilità posturale.'),
('quadriceps', 'zh', '股四头肌', '位于大腿前侧的肌群，由四头（股直肌、股外侧肌、股内侧肌和股中间肌）组成，是膝关节伸展和姿势稳定的关键。'),
('quadriceps', 'ja', '大腿四頭筋', '大腿前側に位置する筋群で、四つの頭（大腿直筋、外側広筋、内側広筋、中間広筋）から成り、膝の伸展と姿勢維持に不可欠です。'),
('quadriceps', 'ko', '대퇴사두근', '허벅지 앞쪽에 위치한 근육군으로 네 개의 근육(대퇴직근, 외측광근, 내측광근, 중간광근)으로 구성되며, 무릎 신전과 자세 유지에 필수적입니다.'),
('quadriceps', 'ar', 'عضلات الفخذ الأمامية (الرباعية)', 'مجموعة عضلية في الجزء الأمامي من الفخذ تتكون من أربعة رؤوس (المستقيمة الفخذية، والمتسعة الوحشية، والإنسية، والمتوسطة)، وهي ضرورية لبسط الركبة واستقرار القوام.'),
('quadriceps', 'hi', 'क्वाड्रिसेप्स', 'जांघ के सामने की मांसपेशी समूह जो चार सिरों (रेक्टस फेमोरिस, वास्टस लेटरलिस, मेडियलिस और इंटरमीडियस) से बनी है, जो घुटने के विस्तार और मुद्रात्मक स्थिरता के लिए आवश्यक है।'),
('quadriceps', 'ru', 'Квадрицепс', 'Мышечная группа передней части бедра, состоящая из четырех головок (прямая, латеральная, медиальная и промежуточная широкие мышцы), необходимая для разгибания колена и стабильности осанки.'),
('quadriceps', 'nl', 'Quadriceps', 'Spiergroep aan de voorzijde van het bovenbeen bestaande uit vier koppen (rectus femoris, vastus lateralis, medialis en intermedius), essentieel voor knie-extensie en houdingsstabiliteit.'),
('quadriceps', 'sv', 'Quadriceps', 'Muskelgrupp på lårts framsida bestående av fyra huvuden (rectus femoris, vastus lateralis, medialis och intermedius), avgörande för knäextension och hållningsstabilitet.'),
('quadriceps', 'pl', 'Mięśnie czworogłowe uda', 'Grupa mięśni przedniej części uda składająca się z czterech głów (prosty uda, obszerny boczny, przyśrodkowy i pośredni), niezbędna do prostowania kolana i stabilizacji postawy.'),
('quadriceps', 'id', 'Kuadrisep', 'Kelompok otot di bagian depan paha yang terdiri dari empat kepala (rektus femoris, vastus lateralis, medialis, dan intermedius), penting untuk ekstensi lutut dan stabilitas postur.'),
('quadriceps', 'bn', 'কোয়াড্রিসেপস', 'উরুর সামনের পেশী গোষ্ঠী যা চারটি মাথা (রেকটাস ফেমোরিস, ভাস্টাস ল্যাটারালিস, মেডিয়ালিস এবং ইন্টারমিডিয়াস) নিয়ে গঠিত, যা হাঁটু সোজা করা এবং শারীরিক স্থিতিশীলতার জন্য গুরুত্বপূর্ণ।'),
('quadriceps', 'vi', 'Cơ tứ đầu đùi', 'Nhóm cơ mặt trước đùi gồm bốn đầu (cơ thẳng đùi, cơ rộng ngoài, trong và giữa), thiết yếu cho việc duỗi gối và ổn định tư thế.'),
('quadriceps', 'fa', 'عضلات چهارسر ران', 'گروه عضلانی بخش قدامی ران متشکل از چهار سر (عضله راست رانی، پهن خارجی، داخلی و میانی)، کلیدی برای باز کردن زانو و ثبات وضعیت بدن.');